import sys

class Solution:
    def longestBitonicSubsequence(self, arr: list[int]) -> int:
        n = len(arr)
        # Compute LIS (Length of Longest Increasing Subsequence)
        lis = [1]*n
        for i in range(1, n):
            for j in range(i):
                if arr[i] > arr[j] and lis[i] < lis[j] + 1:
                    lis[i] = lis[j] + 1

        # Compute LDS (Length of Longest Decreasing Subsequence)
        lds = [1]*n
        for i in range(n-2, -1, -1):
            for j in range(n-1, i, -1):
                if arr[i] > arr[j] and lds[i] < lds[j] + 1:
                    lds[i] = lds[j] + 1

        # Find the maximum sum of LIS and LDS
        return max(x + y - 1 for x, y in zip(lis, lds))

