#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int longestBitonicSubsequence(vector<int>& arr) {
        int n = arr.size();
        vector<int> lis(n, 1), lds(n, 1);
        // Compute LIS (Length of Longest Increasing Subsequence)
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (arr[i] > arr[j] && lis[i] < lis[j] + 1) {
                    lis[i] = lis[j] + 1;
                }
            }
        }
        // Compute LDS (Length of Longest Decreasing Subsequence)
        for (int i = n-2; i >= 0; i--) {
            for (int j = n-1; j > i; j--) {
                if (arr[i] > arr[j] && lds[i] < lds[j] + 1) {
                    lds[i] = lds[j] + 1;
                }
            }
        }
        // Find the maximum sum of LIS and LDS
        int max_len = 0;
        for (int i = 0; i < n; i++) {
            max_len = max(max_len, lis[i] + lds[i] - 1);
        }
        return max_len;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    Solution sol;
    int ans = sol.longestBitonicSubsequence(arr);
    cout << ans << "\n";
    return 0;
}
